397	  -- convert string to real
398	  function from_str(input : string) return real is
399	    constant Nbsp_c       : character := character'val(160);
400	    variable Idx_v        : integer   := input'low;
401	    variable IsNeg_v      : boolean   := false;
402	    variable ValInt_v     : integer   := 0;
403	    variable ValFrac_v    : real      := 0.0;
404	    variable FracDigits_v : integer   := 0;
405	    variable Exp_v        : integer   := 0;
406	    variable ExpNeg_v     : boolean   := false;
407	    variable ValAbs_v     : real      := 0.0;
408	  begin
409	    -- skip leading white-spaces (space, non-breaking space or horizontal tab)
410	    while (Idx_v <= input'high) and (input(Idx_v) = ' ' or input(Idx_v) = Nbsp_c or input(Idx_v) = HT) loop
411	      Idx_v := Idx_v + 1;
412	    end loop;
413	
414	    -- Check sign
415	    if (Idx_v <= input'high) and ((input(Idx_v) = '-') or (input(Idx_v) = '+')) then
416	      IsNeg_v := (input(Idx_v) = '-');
417	      Idx_v   := Idx_v + 1;
418	    end if;
419	
420	    -- Parse Integer
421	    while (Idx_v <= input'high) and (input(Idx_v) <= '9') and (input(Idx_v) >= '0') loop
422	      ValInt_v := ValInt_v * 10 + (character'pos(input(Idx_v)) - character'pos('0'));
423	      Idx_v    := Idx_v + 1;
424	    end loop;
425	
426	    -- Check decimal point
427	    if (Idx_v <= input'high) then
428	      if input(Idx_v) = '.' then
429	        Idx_v := Idx_v + 1;
430	
431	        -- Parse Fractional
432	        while (Idx_v <= input'high) and (input(Idx_v) <= '9') and (input(Idx_v) >= '0') loop
433	          ValFrac_v    := ValFrac_v * 10.0 + real((character'pos(input(Idx_v)) - character'pos('0')));
434	          FracDigits_v := FracDigits_v + 1;
435	          Idx_v        := Idx_v + 1;
436	        end loop;
437	      end if;
438	    end if;
439	
440	    -- Check exponent
441	    if (Idx_v <= input'high) then
442	      if (input(Idx_v) = 'E') or (input(Idx_v) = 'e') then
443	        Idx_v := Idx_v + 1;
444	        -- Check sign
445	        if (Idx_v <= input'high) and ((input(Idx_v) = '-') or (input(Idx_v) = '+')) then
446	          ExpNeg_v := (input(Idx_v) = '-');
447	          Idx_v    := Idx_v + 1;
448	        end if;
449	
450	        -- Parse Integer
451	        while (Idx_v <= input'high) and (input(Idx_v) <= '9') and (input(Idx_v) >= '0') loop
452	          Exp_v := Exp_v * 10 + (character'pos(input(Idx_v)) - character'pos('0'));
453	          Idx_v := Idx_v + 1;
454	        end loop;
455	        if ExpNeg_v then
456	          Exp_v := -Exp_v;
457	        end if;
458	      end if;
459	    end if;
460	
461	    -- Return
462	    ValAbs_v := (real(ValInt_v) + ValFrac_v / 10.0**real(FracDigits_v)) * 10.0**real(Exp_v);
463	    if IsNeg_v then
464	      return -ValAbs_v;
465	    else
466	      return ValAbs_v;
467	    end if;
468	  end function;
