470	  -- convert string to real array
471	  function from_str(input : string) return t_areal is
472	    variable arr      : t_areal(0 to count_array_str_elements(input) - 1) := (others => 0.0);
473	    variable aIdx     : natural                                           := 0;
474	    variable startIdx : natural                                           := 1;
475	    variable endIdx   : natural                                           := 1;
476	    variable idx      : natural                                           := input'low;
477	  begin
478	    while idx <= input'high loop
479	      if input(idx) = ',' then
480	        endIdx    := idx - 1;
481	        arr(aIdx) := from_str(input(startIdx to endIdx));
482	        aIdx      := aIdx + 1;
483	        startIdx  := idx + 1;
484	      end if;
485	      idx := idx + 1;
486	    end loop;
487	    if startIdx <= input'high then
488	      arr(aIdx) := from_str(input(startIdx to input'high));
489	    end if;
490	    return arr;
491	  end function;
