537	    variable max_v : real := 0.0;
538	  begin
539	    for idx in a'low to a'high loop
540	      if max(max_v, a(idx)) > max_v then
541	        max_v := a(idx);
542	      end if;
543	    end loop;
544	    return max_v;
545	  end function;
