569	  end function;
570	
571	  --*** is ratio an integer REAL ***
572	  function is_int_ratio(a : in real; b : in real) return boolean is
573	    variable a_v, b_v : real := 0.0;
574	  begin
575	    -- check > < prior to eval
576	    if a > b then
577	      a_v := real(a);
578	      b_v := real(b);
579	    else
580	      a_v := real(b);
581	      b_v := real(a);
582	    end if;
583	
584	    --eval val
585	    if a_v / b_v = ceil(a_v / b_v) or a_v / b_v = floor(a_v / b_v) then
586	      return true;
587	    else
588	      return false;
589	    end if;
590	  end function;
591	
592	  --*** is ratio an integer REAL ***
593	  function is_int_ratio(a : in integer; b : in integer) return boolean is
594	    variable a_v, b_v : real := 0.0;
595	  begin
596	    -- check > < prior to eval
597	    if a > b then
598	      a_v := real(a);
599	      b_v := real(b);
600	    else
601	      a_v := real(b);
602	      b_v := real(a);
603	    end if;
604	
605	    --eval val
606	    if a_v / b_v = ceil(a_v / b_v) or a_v / b_v = floor(a_v / b_v) then
607	      return true;
608	    else
609	      return false;
610	    end if;
611	
612	  end function;
613	  
614	  --*** find the nearest power 2, used for AXI register count not synth***
615	  function nearest_pow2(a: integer) return integer is
616	      variable power_of_two : unsigned(31 downto 0);    -- Adjust size if needed
617	      variable num_bits     : integer;
618	    begin
619	        num_bits     := 32;
620	        power_of_two := (others => '0');
621	        
622	        for i in 0 to num_bits-1 loop
623	            if (2**i >= a) then
624	                power_of_two    := (others => '0');
625	                power_of_two(i) := '1';
626	                exit;
627	            end if;
628	        end loop;        
629	        return to_integer(power_of_two);   
630	    end function;
